import{_ as e,c as t,o as n,a4 as i}from"./chunks/framework.ttppV29E.js";const o="/assets/create-mcp-server-dialog-server-details.DitRQyrH.png",r="/assets/create-mcp-server-dialog-server-endpoint-config.ghRJcFdP.png",a="/assets/create-mcp-server-dialog-server-save.15cTt3oI.png",s="/assets/mcp-set-default-version-menu.BzwAyEG-.png",d="/assets/mcp-default-version-dialog._KLwKrjw.png",q=JSON.parse('{"title":"Creating an MCP Server","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mcp-servers/creating.md","filePath":"docs/mcp-servers/creating.md","lastUpdated":1776873710000}'),l={name:"docs/mcp-servers/creating.md"},c=i('<h1 id="creating-an-mcp-server" tabindex="-1">Creating an MCP Server <a class="header-anchor" href="#creating-an-mcp-server" aria-label="Permalink to &quot;Creating an MCP Server&quot;">​</a></h1><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before creating an MCP server, you need:</p><ul><li>At least one AireGlu endpoint configured and working</li><li>The <code>create:McpServerConfig</code> permission claim</li><li>The MCP feature enabled for your environment</li></ul><h2 id="create-a-new-server" tabindex="-1">Create a New Server <a class="header-anchor" href="#create-a-new-server" aria-label="Permalink to &quot;Create a New Server&quot;">​</a></h2><ol><li>Navigate to <strong>AI Tools &gt; MCP Servers</strong></li><li>Click the <strong>Create</strong> button in the top-right corner</li><li>The server editor dialog opens with two tabs: <strong>Server Settings</strong> and <strong>Endpoint Configuration</strong></li></ol><p><img src="'+o+'" alt="mcp"></p><h2 id="server-settings-tab" tabindex="-1">Server Settings Tab <a class="header-anchor" href="#server-settings-tab" aria-label="Permalink to &quot;Server Settings Tab&quot;">​</a></h2><h3 id="server-name" tabindex="-1">Server Name <a class="header-anchor" href="#server-name" aria-label="Permalink to &quot;Server Name&quot;">​</a></h3><p><strong>Required.</strong> The unique name for your MCP server. This value is used in the connection URI, so choose something meaningful and URL-friendly.</p><ul><li>1-70 characters</li><li>Letters, numbers, and hyphens only (<code>a-z</code>, <code>A-Z</code>, <code>0-9</code>, <code>-</code>)</li><li>Must be unique across your account</li></ul><p>As you type, a preview of the connection URI is displayed:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Connection URI: https://&lt;runtime-host&gt;/mcp/&lt;tenancy&gt;/&lt;server-name&gt;</span></span></code></pre></div><h3 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h3><p>Optional. Describes what this MCP server provides. This text is surfaced to AI agents to help them understand the server&#39;s purpose. Write a clear, concise summary of the capabilities exposed.</p><h3 id="version" tabindex="-1">Version <a class="header-anchor" href="#version" aria-label="Permalink to &quot;Version&quot;">​</a></h3><p><strong>Required.</strong> A semantic version number in the format <code>X.Y.Z</code> (e.g. <code>1.0.0</code>). Each server must have at least one version. Versions must be unique within the server.</p><h3 id="set-as-default-version" tabindex="-1">Set as Default Version <a class="header-anchor" href="#set-as-default-version" aria-label="Permalink to &quot;Set as Default Version&quot;">​</a></h3><p>When checked, this version is used when an MCP client connects without specifying a version in the URI.</p><ul><li>URI with version: <code>https://&lt;host&gt;/mcp/&lt;tenant&gt;/&lt;name&gt;/1.0.0</code></li><li>URI without version: <code>https://&lt;host&gt;/mcp/&lt;tenant&gt;/&lt;name&gt;</code> (uses default)</li></ul><h2 id="endpoint-configuration-tab" tabindex="-1">Endpoint Configuration Tab <a class="header-anchor" href="#endpoint-configuration-tab" aria-label="Permalink to &quot;Endpoint Configuration Tab&quot;">​</a></h2><p>This tab is where you map your AireGlu endpoints to MCP tools and resources. See <a href="./tools-and-resources.html">Tools and Resources</a> for a detailed explanation of the two exposure types.</p><p><img src="'+r+'" alt="mcp"></p><h3 id="adding-an-endpoint" tabindex="-1">Adding an Endpoint <a class="header-anchor" href="#adding-an-endpoint" aria-label="Permalink to &quot;Adding an Endpoint&quot;">​</a></h3><ol><li>Click the <strong>Add endpoint</strong> button</li><li>An inline form appears with the fields described below</li><li>Fill in the required fields</li><li>Click <strong>Done</strong> to confirm the endpoint, or <strong>Cancel</strong> to discard it</li></ol><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Only one endpoint can be edited at a time. The <strong>Add endpoint</strong> button is hidden while the inline form is open.</p></div><h4 id="name" tabindex="-1">Name <a class="header-anchor" href="#name" aria-label="Permalink to &quot;Name&quot;">​</a></h4><p><strong>Required.</strong> The name AI agents will see for this tool or resource. Choose a descriptive, action-oriented name.</p><ul><li>1-64 characters</li><li>Letters, numbers, underscores, and hyphens only (<code>a-z</code>, <code>A-Z</code>, <code>0-9</code>, <code>_</code>, <code>-</code>)</li><li>Must be unique within the version (case-insensitive)</li></ul><h4 id="target-endpoint" tabindex="-1">Target Endpoint <a class="header-anchor" href="#target-endpoint" aria-label="Permalink to &quot;Target Endpoint&quot;">​</a></h4><p><strong>Required.</strong> Select an existing AireGlu endpoint from the searchable dropdown. This is the endpoint that will be executed when the AI agent invokes the tool or reads the resource.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Endpoints using Callback or AdapterCallback input modes cannot be exposed via MCP.</p></div><h4 id="endpoint-version" tabindex="-1">Endpoint Version <a class="header-anchor" href="#endpoint-version" aria-label="Permalink to &quot;Endpoint Version&quot;">​</a></h4><p><strong>Required.</strong> Select which version of the target endpoint to use. The dropdown is populated after selecting a target endpoint. Selecting <strong>default</strong> uses the endpoint&#39;s default version.</p><p>This field is disabled until a target endpoint is selected. Changing the target endpoint resets the version selection.</p><h4 id="exposure-type" tabindex="-1">Exposure Type <a class="header-anchor" href="#exposure-type" aria-label="Permalink to &quot;Exposure Type&quot;">​</a></h4><p>Choose how this endpoint is exposed to AI agents:</p><ul><li><strong>Tool</strong> - An action the agent can invoke (e.g. send an email, run a query)</li><li><strong>Resource</strong> - Data the agent can read (e.g. fetch records, retrieve a document)</li></ul><p>A help icon next to the label provides a tooltip summary of the difference. See <a href="./tools-and-resources.html">Tools and Resources</a> for full details.</p><h4 id="description-1" tabindex="-1">Description <a class="header-anchor" href="#description-1" aria-label="Permalink to &quot;Description&quot;">​</a></h4><p>Optional but recommended. Tells the AI agent what this endpoint does and when to use it. A clear description directly improves the agent&#39;s ability to select the right tool or resource.</p><h4 id="resource-uri-resource-type-only" tabindex="-1">Resource URI (Resource type only) <a class="header-anchor" href="#resource-uri-resource-type-only" aria-label="Permalink to &quot;Resource URI (Resource type only)&quot;">​</a></h4><p><strong>Required for Resources.</strong> A unique URI identifying this resource. Use a descriptive scheme such as:</p><ul><li><code>data://patient-records</code></li><li><code>file://config.json</code></li><li><code>aireglu://my-server/lookup</code></li></ul><p>Must be unique within the version (case-insensitive).</p><h4 id="mime-type-resource-type-only" tabindex="-1">Mime Type (Resource type only) <a class="header-anchor" href="#mime-type-resource-type-only" aria-label="Permalink to &quot;Mime Type (Resource type only)&quot;">​</a></h4><p>The content type of the resource response. Defaults to <code>application/json</code>. Other common values: <code>text/plain</code>, <code>application/xml</code>, <code>text/html</code>.</p><h3 id="editing-an-endpoint" tabindex="-1">Editing an Endpoint <a class="header-anchor" href="#editing-an-endpoint" aria-label="Permalink to &quot;Editing an Endpoint&quot;">​</a></h3><p>Click the edit icon on an endpoint row in the table. The inline form opens pre-populated with the endpoint&#39;s current values. Make changes and click <strong>Done</strong> to save, or <strong>Cancel</strong> to revert to the previous values.</p><h3 id="endpoints-table" tabindex="-1">Endpoints Table <a class="header-anchor" href="#endpoints-table" aria-label="Permalink to &quot;Endpoints Table&quot;">​</a></h3><p>After adding endpoints, they appear in the summary table showing:</p><table><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Name</td><td>The exposed name</td></tr><tr><td>Target Endpoint</td><td>The underlying AireGlu endpoint</td></tr><tr><td>Version</td><td>The endpoint version in use</td></tr><tr><td>Type</td><td>Tool or Resource</td></tr><tr><td>Active</td><td>Toggle to enable/disable individual Tools or Resources</td></tr><tr><td>Actions</td><td>Edit or Delete icons</td></tr></tbody></table><p><img src="'+a+'" alt="mcp"></p><h2 id="saving" tabindex="-1">Saving <a class="header-anchor" href="#saving" aria-label="Permalink to &quot;Saving&quot;">​</a></h2><p>Click <strong>Save</strong> to create the MCP server. The server appears in the list and is immediately available for MCP clients to connect to (provided both the server and version are active).</p><h2 id="editing-an-existing-server" tabindex="-1">Editing an Existing Server <a class="header-anchor" href="#editing-an-existing-server" aria-label="Permalink to &quot;Editing an Existing Server&quot;">​</a></h2><ol><li>Expand the server in the list to see its versions</li><li>Click the three-dot menu on the server row and select <strong>Edit</strong></li><li>The edit dialog opens with the same tabs. The server name cannot be changed after creation.</li></ol><p>To edit a specific version, click the three-dot menu on the version row and select <strong>Edit version</strong>.</p><h3 id="server-actions-menu" tabindex="-1">Server Actions Menu <a class="header-anchor" href="#server-actions-menu" aria-label="Permalink to &quot;Server Actions Menu&quot;">​</a></h3><p>The three-dot menu on the server row provides the following options:</p><table><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td>Edit</td><td>Open the server editor dialog</td></tr><tr><td>Copy URL</td><td>Copy the MCP connection URI to the clipboard</td></tr><tr><td>Copy Client Config</td><td>Copy a ready-to-paste client configuration (see <a href="./connecting-clients.html">Connecting Clients</a>)</td></tr><tr><td>Export</td><td>Copy the full server configuration as JSON to the clipboard</td></tr><tr><td>Set Default Version</td><td>Open a dialog to change which version is used when no version is specified in the URI</td></tr><tr><td>Delete</td><td>Delete the server (with confirmation)</td></tr></tbody></table><h3 id="version-actions-menu" tabindex="-1">Version Actions Menu <a class="header-anchor" href="#version-actions-menu" aria-label="Permalink to &quot;Version Actions Menu&quot;">​</a></h3><p>The three-dot menu on a version row provides:</p><table><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td>Edit version</td><td>Open the editor for this specific version</td></tr><tr><td>Add version</td><td>Create a new version on this server</td></tr><tr><td>Copy Client Config</td><td>Copy client config targeting this specific version</td></tr></tbody></table><h2 id="setting-the-default-version" tabindex="-1">Setting the Default Version <a class="header-anchor" href="#setting-the-default-version" aria-label="Permalink to &quot;Setting the Default Version&quot;">​</a></h2><p>The default version is used when an MCP client connects without specifying a version in the URI. You can set it in two ways:</p><ol><li><strong>During creation</strong> — Check the <strong>Set as Default Version</strong> checkbox in the Server Settings tab</li><li><strong>After creation</strong> — Click the three-dot menu on the server row and select <strong>Set Default Version</strong></li></ol><p>The Set Default Version dialog shows the current default and a dropdown to select a new one. Select <strong>None</strong> to clear the default entirely.</p><p><img src="'+s+'" alt="mcp"><img src="'+d+'" alt="mcp"></p><p>The default version is indicated by a <strong>Default</strong> chip next to the version number in the list.</p><h2 id="adding-a-new-version" tabindex="-1">Adding a New Version <a class="header-anchor" href="#adding-a-new-version" aria-label="Permalink to &quot;Adding a New Version&quot;">​</a></h2><ol><li>Expand the server in the list</li><li>Click the three-dot menu on any version row and select <strong>Add version</strong></li><li>Enter a new version number and configure endpoints</li><li>Optionally set the new version as the default</li></ol><h2 id="activating-and-deactivating" tabindex="-1">Activating and Deactivating <a class="header-anchor" href="#activating-and-deactivating" aria-label="Permalink to &quot;Activating and Deactivating&quot;">​</a></h2><h3 id="server-level" tabindex="-1">Server Level <a class="header-anchor" href="#server-level" aria-label="Permalink to &quot;Server Level&quot;">​</a></h3><p>Toggle the <strong>Active</strong> switch on the server row to enable or disable the entire server. A deactivated server rejects all MCP client connections.</p><h3 id="version-level" tabindex="-1">Version Level <a class="header-anchor" href="#version-level" aria-label="Permalink to &quot;Version Level&quot;">​</a></h3><p>Toggle the <strong>Active</strong> switch on a version row to enable or disable that version. Inactive versions return an error when requested directly and are excluded from the default version fallback.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use version-level deactivation to deprecate old versions while keeping the server online for clients using newer versions.</p></div><h2 id="warning-indicators" tabindex="-1">Warning Indicators <a class="header-anchor" href="#warning-indicators" aria-label="Permalink to &quot;Warning Indicators&quot;">​</a></h2><p>The server list displays warning icons in two situations:</p><ul><li><strong>No endpoints configured</strong> — A version has no exposed endpoints. A warning icon appears on the version row.</li><li><strong>Missing target endpoints</strong> — A version references AireGlu endpoints that no longer exist (e.g. deleted or renamed). The warning tooltip lists the missing endpoint names.</li></ul><p>These warnings appear on active versions only. Resolve them by editing the version to add or fix endpoint mappings.</p>',82),h=[c];function p(u,g,v,m,b,f){return n(),t("div",null,h)}const w=e(l,[["render",p]]);export{q as __pageData,w as default};
